import { Component, OnInit, ChangeDetectorRef } from '@angular/core';
import { ChartConfiguration } from 'chart.js';
import { BaseChartDirective } from 'ng2-charts'; // ✅ FIX: Added missing import
import { forkJoin, finalize } from 'rxjs';

import { AdminAnalyticsApiService } from '../../../core/services/admin-analytics-api.service';
import {
  AdminLoanAnalyticsResponse,
  AdminTransactionAnalyticsResponse
} from '../../../core/model/all';

import { MatFormFieldModule } from '@angular/material/form-field';
import { MatSelectModule } from '@angular/material/select';
import { FormsModule } from '@angular/forms';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'app-admin-analytics',
  standalone: true,
  imports: [
    FormsModule,
    MatFormFieldModule,
    MatSelectModule,
    CommonModule,
    BaseChartDirective // ✅ FIX: Added BaseChartDirective to imports
  ],
  templateUrl: './admin-analytics.html',
  styleUrl: './admin-analytics.css',
})
export class AdminAnalytics implements OnInit {

  loading = false;
  selectedTimeframe = '7d';

  totalInflow = 0;
  totalOutflow = 0;
  averageTicketSize = 0;
  totalLoans = 0;
  npaCount = 0;
  npaRatio = 0;

  constructor(
    private adminAnalyticsApi: AdminAnalyticsApiService,
    private cd: ChangeDetectorRef // ✅ IMPORTANT FIX
  ) {}

  ngOnInit(): void {
    this.loadAnalytics();
  }

  onTimeframeChange(): void {
    this.loadAnalytics();
  }

  // ✅ FIXED METHOD
  loadAnalytics(): void {
    this.loading = true;

    forkJoin({
      transaction: this.adminAnalyticsApi.getTransactionAnalytics(this.selectedTimeframe),
      loan: this.adminAnalyticsApi.getLoanAnalytics(this.selectedTimeframe)
    })
      .pipe(
        finalize(() => {
          this.loading = false;

          // ✅ CRITICAL: Prevents NG0100 error
          this.cd.detectChanges();
        })
      )
      .subscribe({
        next: ({ transaction, loan }) => {
          this.bindTransactionAnalytics(transaction);
          this.bindLoanAnalytics(loan);
        },
        error: () => {
          // optional: handle error UI
        }
      });
  }

  // -----------------------------
  // Charts Data
  // -----------------------------

  transactionLineChartData: ChartConfiguration<'line'>['data'] = {
    labels: [],
    datasets: [
      { 
        data: [], 
        label: 'Inflow', 
        tension: 0.4,
        borderColor: '#00c896',
        backgroundColor: 'rgba(0, 200, 150, 0.1)',
        borderWidth: 2
      },
      { 
        data: [], 
        label: 'Outflow', 
        tension: 0.4,
        borderColor: '#ff3b3b',
        backgroundColor: 'rgba(255, 59, 59, 0.1)',
        borderWidth: 2
      }
    ]
  };

  transactionLineChartOptions: ChartConfiguration<'line'>['options'] = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        position: 'top',
        labels: {
          usePointStyle: true,
          padding: 15
        }
      }
    },
    scales: {
      y: {
        beginAtZero: true
      }
    }
  };

  loanBarChartData: ChartConfiguration<'bar'>['data'] = {
    labels: [],
    datasets: [
      { 
        data: [], 
        label: 'Loans by Status',
        backgroundColor: '#3b82f6',
        borderColor: '#1e40af',
        borderWidth: 1
      }
    ]
  };

  loanBarChartOptions: ChartConfiguration<'bar'>['options'] = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        position: 'top',
        labels: {
          usePointStyle: true,
          padding: 15
        }
      }
    },
    scales: {
      y: {
        beginAtZero: true
      }
    }
  };

  productBarChartData: ChartConfiguration<'bar'>['data'] = {
    labels: [],
    datasets: [
      { 
        data: [], 
        label: 'Loans by Product',
        backgroundColor: '#10b981',
        borderColor: '#059669',
        borderWidth: 1
      }
    ]
  };

  productBarChartOptions: ChartConfiguration<'bar'>['options'] = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        position: 'top',
        labels: {
          usePointStyle: true,
          padding: 15
        }
      }
    },
    scales: {
      y: {
        beginAtZero: true
      }
    }
  };

  // -----------------------------
  // Bind Data Methods
  // -----------------------------

  private bindTransactionAnalytics(response: AdminTransactionAnalyticsResponse): void {
    this.totalInflow = response.totalInflow || 0;
    this.totalOutflow = response.totalOutflow || 0;
    this.averageTicketSize = response.averageTicketSize || 0;

    const labels = response.dailyVolumes?.map(item => item.date) || [];
    const inflowData = response.dailyVolumes?.map(item => item.inflow) || [];
    const outflowData = response.dailyVolumes?.map(item => item.outflow) || [];

    this.transactionLineChartData = {
      labels,
      datasets: [
        { 
          data: inflowData, 
          label: 'Inflow', 
          tension: 0.4,
          borderColor: '#00c896',
          backgroundColor: 'rgba(0, 200, 150, 0.1)',
          borderWidth: 2
        },
        { 
          data: outflowData, 
          label: 'Outflow', 
          tension: 0.4,
          borderColor: '#ff3b3b',
          backgroundColor: 'rgba(255, 59, 59, 0.1)',
          borderWidth: 2
        }
      ]
    };
  }

  private bindLoanAnalytics(response: AdminLoanAnalyticsResponse): void {
    this.totalLoans = response.totalLoans || 0;
    this.npaCount = response.npaCount || 0;
    this.npaRatio = response.npaRatio || 0;

    const statusLabels = Object.keys(response.loanDistributionByStatus || {});
    const statusValues = Object.values(response.loanDistributionByStatus || {});

    this.loanBarChartData = {
      labels: statusLabels,
      datasets: [
        { 
          data: statusValues, 
          label: 'Loans by Status',
          backgroundColor: '#3b82f6',
          borderColor: '#1e40af',
          borderWidth: 1
        }
      ]
    };

    const productLabels = Object.keys(response.loanDistributionByProduct || {});
    const productValues = Object.values(response.loanDistributionByProduct || {});

    this.productBarChartData = {
      labels: productLabels,
      datasets: [
        { 
          data: productValues, 
          label: 'Loans by Product',
          backgroundColor: '#10b981',
          borderColor: '#059669',
          borderWidth: 1
        }
      ]
    };
  }
}